import React, { useState } from "react";
import {
  BrowserRouter,
  Routes,
  Route,
  useNavigate,
} from "react-router-dom";

import emailjs from "@emailjs/browser";

import "./App.css";

function Login() {
  const navigate = useNavigate();

  const [email, setEmail] =
    useState("");

  const [password, setPassword] =
    useState("");

  const [emailError, setEmailError] =
    useState("");

  const [
    passwordError,
    setPasswordError,
  ] = useState("");

  const validateLogin = () => {
    let valid = true;

    setEmailError("");
    setPasswordError("");

    const emailPattern =
      /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

    if (!email) {
      setEmailError(
        "Email is required"
      );
      valid = false;
    } else if (
      !emailPattern.test(email)
    ) {
      setEmailError(
        "Enter valid email with @"
      );
      valid = false;
    }

    if (!password) {
      setPasswordError(
        "Password is required"
      );
      valid = false;
    } else if (
      password.length < 6
    ) {
      setPasswordError(
        "Password must be at least 6 characters"
      );
      valid = false;
    }

    if (valid) {
      emailjs
        .send(
          "service_gk91tep",
          "template_hqu6lt8",
          {
            user_email: email,
            time:
              new Date().toLocaleString(),
          },
          "omkPXdWy353_kaQ2s"
        )
        .then(() => {
          alert(
            "Login successful and email sent!"
          );
        })
        .catch((error) => {
          console.log(error);

          alert(
            "Login successful but email failed."
          );
        });
    }
  };

  return (
    <div className="page">
      <div className="phone-card">
        <div className="top-shape"></div>

        <h1>Welcome</h1>

        <p className="subtitle">
          Sign in to continue
        </p>

        <div className="form">
          <label>Email</label>

          <input
            type="text"
            placeholder="your email address goes here"
            value={email}
            onChange={(e) =>
              setEmail(
                e.target.value
              )
            }
          />

          {emailError && (
            <p className="error">
              {emailError}
            </p>
          )}

          <label>Password</label>

          <input
            type="password"
            placeholder="••••••••"
            value={password}
            onChange={(e) =>
              setPassword(
                e.target.value
              )
            }
          />

          {passwordError && (
            <p className="error">
              {passwordError}
            </p>
          )}

          <p
            className="forgot"
            onClick={() =>
              navigate(
                "/forgot-password"
              )
            }
          >
            Forgot Password?
          </p>

          <button
            onClick={validateLogin}
          >
            Sign in
          </button>

          <p className="or">OR</p>

          <p>Connect with</p>

          <div className="socials">
            G | f
          </div>

          <p className="bottom-text">
            Don’t have Account?{" "}
            <span
              onClick={() =>
                navigate(
                  "/register"
                )
              }
            >
              Sign up
            </span>
          </p>
        </div>
      </div>
    </div>
  );
}

function Register() {
  const navigate = useNavigate();

  return (
    <div className="page">
      <div className="phone-card">
        <div
          className="back-button"
          onClick={() =>
            navigate("/")
          }
        >
          ← Back
        </div>

        <div className="top-shape"></div>

        <h1>Create Account</h1>

        <div className="form">
          <label>Name</label>

          <input
            type="text"
            placeholder="your full name goes here"
          />

          <label>Email</label>

          <input
            type="text"
            placeholder="your email address goes here"
          />

          <label>Phone</label>

          <input
            type="text"
            placeholder="your phone number here"
          />

          <label>Password</label>

          <input
            type="password"
            placeholder="••••••••"
          />

          <button>
            Sign up
          </button>

          <p className="or">OR</p>

          <p>
            Create account with
          </p>

          <div className="socials">
            G | f
          </div>

          <p className="bottom-text">
            Already Have an account?{" "}
            <span
              onClick={() =>
                navigate("/")
              }
            >
              Sign in
            </span>
          </p>
        </div>
      </div>
    </div>
  );
}

function ForgotPassword() {
  const navigate = useNavigate();

  return (
    <div className="page">
      <div className="phone-card">
        <div
          className="back-button"
          onClick={() =>
            navigate("/")
          }
        >
          ← Back
        </div>

        <div className="top-shape"></div>

        <h1>Reset Password</h1>

        <p className="subtitle">
          Enter your email to reset
          password
        </p>

        <div className="form">
          <label>Email</label>

          <input
            type="email"
            placeholder="your email address goes here"
          />

          <button>
            Send Reset Link
          </button>

          <p className="bottom-text">
            Remember password?{" "}
            <span
              onClick={() =>
                navigate("/")
              }
            >
              Sign in
            </span>
          </p>
        </div>
      </div>
    </div>
  );
}

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route
          path="/"
          element={<Login />}
        />

        <Route
          path="/register"
          element={<Register />}
        />

        <Route
          path="/forgot-password"
          element={
            <ForgotPassword />
          }
        />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
